sql:
SELECT AVG(kills) AS avg_kills, AVG(blocks) AS avg_blocks
FROM team_game_statistics
WHERE team_id = 1;

SELECT game_id, SUM(kills) AS total_kills, MAX(digs) AS max_digs
FROM team_game_statistics
GROUP BY game_id;

